import React, { useState, useEffect, useContext, useCallback } from 'react';
import {
  BrowserRouter as Router,
  Routes,
  Route,
  Navigate,
  Link,
  useNavigate,
  useLocation
} from 'react-router-dom';
import {
  ThemeProvider,
  createTheme,
  CssBaseline,
  AppBar,
  Toolbar,
  Typography,
  Button,
  Box,
  Card,
  CardContent,
  TextField,
  IconButton,
  Drawer,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  CircularProgress,
  Alert,
  Grid,
  LinearProgress,
  Chip,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Paper,
  Container,
  Avatar,
  Divider,
  CardActions,
  Stack,
  Fade,
  Grow,
  Zoom,
  ToggleButton,
  ToggleButtonGroup,
  FormControl,
  InputLabel,
  Select,
  MenuItem
} from '@mui/material';
import { alpha } from '@mui/material/styles';
import {
  Menu as MenuIcon,
  Dashboard as DashboardIcon,
  Upload as UploadIcon,
  Assessment as AssessmentIcon,
  Work as WorkIcon,
  History as HistoryIcon,
  Logout as LogoutIcon,
  Analytics as AnalyticsIcon,
  CheckCircle as CheckCircleIcon,
  TrendingUp as TrendingUpIcon,
  Description as DescriptionIcon,
  CloudUpload as CloudUploadIcon,
  Rocket as RocketIcon,
  Add as AddIcon,
  AutoAwesome as AutoAwesomeIcon,
  Psychology as PsychologyIcon,
  InsertDriveFile as InsertDriveFileIcon,
  PictureAsPdf as PictureAsPdfIcon,
  Article as ArticleIcon,
  Search as SearchIcon,
  Warning as WarningIcon,
  AppRegistration as AppRegistrationIcon,
  Delete as DeleteIcon,
  Refresh as RefreshIcon,
  Error as ErrorIcon,
  LocationOn as LocationIcon,
  AttachMoney as MoneyIcon,
  Email as EmailIcon,
  FileCopy as FileCopyIcon,
  Timeline as TimelineIcon,
  Lightbulb as LightbulbIcon
} from '@mui/icons-material';
import axios from 'axios';

// ==================== API CONFIGURATION ====================

const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:8000/api';

const api = axios.create({
  baseURL: API_BASE_URL,
  headers: { 'Content-Type': 'application/json' }
});

api.interceptors.request.use((config) => {
  const token = localStorage.getItem('access_token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response?.status === 401) {
      localStorage.removeItem('access_token');
      window.location.href = '/login';
    }
    return Promise.reject(error);
  }
);

// ==================== THEME ====================

const theme = createTheme({
  palette: {
    mode: 'light',
    primary: { main: '#ff69b4', light: '#ff9acb', dark: '#ff1493' },
    secondary: { main: '#ff6b6b', light: '#ff8787', dark: '#fa5252' },
    success: { main: '#51cf66', light: '#69db7e', dark: '#37b24d' },
    warning: { main: '#ff922b', light: '#ffa94d', dark: '#f76707' },
    error: { main: '#ff6b6b', light: '#ff8787', dark: '#fa5252' },
    background: { default: '#fff5f8', paper: '#ffffff' },
  },
  typography: {
    fontFamily: '"Inter", "Poppins", "Roboto", sans-serif',
    h4: { fontWeight: 700 },
    h5: { fontWeight: 600 },
    h6: { fontWeight: 600 },
  },
  shape: { borderRadius: 16 },
  components: {
    MuiButton: {
      styleOverrides: {
        root: { textTransform: 'none', fontWeight: 600, borderRadius: 12, padding: '8px 20px' }
      }
    },
    MuiCard: {
      styleOverrides: {
        root: { borderRadius: 20, boxShadow: '0 4px 24px rgba(255,105,180,0.08)', transition: 'all 0.3s ease' }
      }
    },
  },
});

// ==================== AUTH CONTEXT ====================

const AuthContext = React.createContext(null);

const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const token = localStorage.getItem('access_token');
    if (token) {
      api.get('/auth/profile')
        .then(res => setUser(res.data))
        .catch(() => {
          localStorage.removeItem('access_token');
          setUser(null);
        })
        .finally(() => setLoading(false));
    } else {
      setLoading(false);
    }
  }, []);

  const login = async (username, password) => {
    const formData = new FormData();
    formData.append('username', username);
    formData.append('password', password);
    const res = await axios.post(`${API_BASE_URL}/auth/login`, formData, {
      headers: { 'Content-Type': 'multipart/form-data' }
    });
    localStorage.setItem('access_token', res.data.access_token);
    const profile = await api.get('/auth/profile');
    setUser(profile.data);
    return profile.data;
  };

  const signup = async (userData) => {
    const res = await api.post('/auth/signup', userData);
    return res.data;
  };

  const logout = () => {
    localStorage.removeItem('access_token');
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, login, signup, logout, loading }}>
      {children}
    </AuthContext.Provider>
  );
};

const useAuth = () => useContext(AuthContext);

// ==================== CUSTOM DROP ZONE ====================

const FileDropZone = ({ onFileChange, file }) => {
  const [dragging, setDragging] = useState(false);

  const handleDrop = useCallback((e) => {
    e.preventDefault();
    setDragging(false);
    const dropped = e.dataTransfer.files[0];
    if (dropped) onFileChange(dropped);
  }, [onFileChange]);

  const handleDragOver = (e) => { e.preventDefault(); setDragging(true); };
  const handleDragLeave = () => setDragging(false);

  const handleInputChange = (e) => {
    if (e.target.files[0]) onFileChange(e.target.files[0]);
  };

  return (
    <Box
      onDrop={handleDrop}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onClick={() => document.getElementById('resume-file-input').click()}
      sx={{
        border: `2px dashed ${dragging ? '#ff1493' : '#ff69b4'}`,
        borderRadius: 3,
        p: 5,
        textAlign: 'center',
        cursor: 'pointer',
        bgcolor: dragging ? alpha('#ff69b4', 0.08) : alpha('#ff69b4', 0.03),
        transition: 'all 0.2s ease',
        '&:hover': { bgcolor: alpha('#ff69b4', 0.06), borderColor: '#ff1493' }
      }}
    >
      <input
        id="resume-file-input"
        type="file"
        accept=".pdf,.docx"
        style={{ display: 'none' }}
        onChange={handleInputChange}
      />
      {file ? (
        <Box>
          <CheckCircleIcon sx={{ fontSize: 48, color: 'success.main', mb: 1 }} />
          <Typography variant="h6" color="success.main">{file.name}</Typography>
          <Typography variant="body2" color="text.secondary">
            {(file.size / 1024 / 1024).toFixed(2)} MB — Click to change
          </Typography>
        </Box>
      ) : (
        <Box>
          <CloudUploadIcon sx={{ fontSize: 56, color: '#ff69b4', mb: 1 }} />
          <Typography variant="h6" gutterBottom>Drag & drop your resume here</Typography>
          <Typography variant="body2" color="text.secondary">or click to browse</Typography>
          <Box display="flex" justifyContent="center" gap={1} mt={2}>
            <Chip icon={<PictureAsPdfIcon />} label="PDF" size="small" sx={{ bgcolor: alpha('#ff69b4', 0.1) }} />
            <Chip icon={<ArticleIcon />} label="DOCX" size="small" sx={{ bgcolor: alpha('#ff69b4', 0.1) }} />
          </Box>
          <Typography variant="caption" color="text.secondary" display="block" mt={1}>Max 10MB</Typography>
        </Box>
      )}
    </Box>
  );
};

// ==================== JOB BOARD COMPONENT ====================

const JobBoardPage = () => {
  const [resumes, setResumes] = useState([]);
  const [selectedResume, setSelectedResume] = useState('');
  const [keywords, setKeywords] = useState('');
  const [location, setLocation] = useState('');
  const [jobType, setJobType] = useState('');
  const [jobs, setJobs] = useState([]);
  const [loading, setLoading] = useState(false);
  const [selectedJob, setSelectedJob] = useState(null);
  const [dialogOpen, setDialogOpen] = useState(false);

  useEffect(() => { fetchResumes(); }, []);

  const fetchResumes = async () => {
    try {
      const res = await api.get('/resume/list');
      setResumes(res.data);
    } catch (err) { console.error(err); }
  };

  const searchJobs = async () => {
    if (!selectedResume) {
      alert('Please select a resume first');
      return;
    }
    setLoading(true);
    try {
      const res = await api.post('/jobs/search', {
        resume_id: parseInt(selectedResume),
        keywords: keywords,
        location: location,
        job_type: jobType,
        limit: 20
      });
      setJobs(res.data.jobs || []);
    } catch (err) {
      console.error('Job search failed:', err);
      alert('Failed to search jobs');
    } finally {
      setLoading(false);
    }
  };

  const getMatchColor = (score) => {
    if (score >= 80) return '#4caf50';
    if (score >= 60) return '#ff9800';
    return '#f44336';
  };

  return (
    <Box>
      <Typography variant="h4" gutterBottom>Job Board</Typography>
      <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>
        Find jobs that match your skills and experience
      </Typography>

      <Grid container spacing={4}>
        <Grid item xs={12} md={4}>
          <Card sx={{ p: 3, position: 'sticky', top: 80 }}>
            <Typography variant="h6" gutterBottom>Search Criteria</Typography>

            <FormControl fullWidth sx={{ mb: 2 }}>
              <InputLabel>Select Resume</InputLabel>
              <Select
                value={selectedResume}
                onChange={(e) => setSelectedResume(e.target.value)}
                label="Select Resume"
              >
                {resumes.map(r => (
                  <MenuItem key={r.id} value={String(r.id)}>
                    {r.name || r.filename}
                  </MenuItem>
                ))}
              </Select>
            </FormControl>

            <TextField
              fullWidth
              label="Keywords (optional)"
              value={keywords}
              onChange={(e) => setKeywords(e.target.value)}
              placeholder="e.g., Python, React, AWS"
              sx={{ mb: 2 }}
            />

            <TextField
              fullWidth
              label="Location"
              value={location}
              onChange={(e) => setLocation(e.target.value)}
              placeholder="e.g., Remote, New York, SF"
              sx={{ mb: 2 }}
            />

            <FormControl fullWidth sx={{ mb: 2 }}>
              <InputLabel>Job Type</InputLabel>
              <Select
                value={jobType}
                onChange={(e) => setJobType(e.target.value)}
                label="Job Type"
              >
                <MenuItem value="">All</MenuItem>
                <MenuItem value="full-time">Full-time</MenuItem>
                <MenuItem value="remote">Remote</MenuItem>
                <MenuItem value="hybrid">Hybrid</MenuItem>
                <MenuItem value="contract">Contract</MenuItem>
              </Select>
            </FormControl>

            <Button
              variant="contained"
              fullWidth
              onClick={searchJobs}
              disabled={loading || !selectedResume}
              startIcon={loading ? <CircularProgress size={18} /> : <SearchIcon />}
            >
              {loading ? 'Searching...' : 'Search Jobs'}
            </Button>
          </Card>
        </Grid>

        <Grid item xs={12} md={8}>
          {jobs.length === 0 && !loading && (
            <Card sx={{ textAlign: 'center', py: 10 }}>
              <WorkIcon sx={{ fontSize: 80, color: alpha('#ff69b4', 0.3), mb: 2 }} />
              <Typography variant="h6" gutterBottom>No jobs found</Typography>
              <Typography variant="body2" color="text.secondary">
                Select a resume and click "Search Jobs" to find matching positions
              </Typography>
            </Card>
          )}

          {loading && (
            <Card sx={{ p: 4, textAlign: 'center' }}>
              <CircularProgress sx={{ color: '#ff69b4' }} />
              <Typography sx={{ mt: 2 }}>Finding jobs for you...</Typography>
            </Card>
          )}

          <Grid container spacing={2}>
            {jobs.map((job) => (
              <Grid item xs={12} key={job.id}>
                <Card sx={{ '&:hover': { transform: 'translateY(-2px)', transition: 'transform 0.2s' } }}>
                  <CardContent>
                    <Box display="flex" justifyContent="space-between" alignItems="flex-start">
                      <Box flex={1}>
                        <Typography variant="h6" fontWeight={600}>{job.title}</Typography>
                        <Typography variant="body2" color="primary" gutterBottom>
                          {job.company} • {job.location}
                        </Typography>
                        <Box display="flex" gap={1} flexWrap="wrap" mb={1}>
                          <Chip label={job.job_type} size="small" sx={{ bgcolor: alpha('#ff69b4', 0.1) }} />
                          <Chip
                            label={`Match: ${job.match_score}%`}
                            size="small"
                            sx={{ bgcolor: alpha(getMatchColor(job.match_score), 0.1), color: getMatchColor(job.match_score) }}
                          />
                          {job.salary_min && (
                            <Chip
                              icon={<MoneyIcon />}
                              label={`$${job.salary_min.toLocaleString()} - $${job.salary_max.toLocaleString()}`}
                              size="small"
                            />
                          )}
                        </Box>
                        <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
                          {job.description?.substring(0, 200)}...
                        </Typography>
                        <Box display="flex" flexWrap="wrap" gap={0.5}>
                          {job.skills_required?.slice(0, 5).map((skill, i) => (
                            <Chip key={i} label={skill} size="small" variant="outlined" />
                          ))}
                        </Box>
                      </Box>
                      <Button
                        variant="outlined"
                        onClick={() => { setSelectedJob(job); setDialogOpen(true); }}
                      >
                        View Details
                      </Button>
                    </Box>
                  </CardContent>
                </Card>
              </Grid>
            ))}
          </Grid>
        </Grid>
      </Grid>

      <Dialog open={dialogOpen} onClose={() => setDialogOpen(false)} maxWidth="md" fullWidth>
        {selectedJob && (
          <>
            <DialogTitle>
              <Typography variant="h5">{selectedJob.title}</Typography>
              <Typography variant="subtitle1" color="primary">{selectedJob.company}</Typography>
            </DialogTitle>
            <DialogContent dividers>
              <Grid container spacing={2}>
                <Grid item xs={12}>
                  <Chip label={selectedJob.location} icon={<LocationIcon />} sx={{ mr: 1 }} />
                  <Chip label={selectedJob.job_type} sx={{ mr: 1 }} />
                  {selectedJob.salary_min && (
                    <Chip label={`$${selectedJob.salary_min.toLocaleString()} - $${selectedJob.salary_max.toLocaleString()}`} icon={<MoneyIcon />} />
                  )}
                </Grid>
                <Grid item xs={12}>
                  <Typography variant="h6">Job Description</Typography>
                  <Typography variant="body2" paragraph>{selectedJob.description}</Typography>
                </Grid>
                <Grid item xs={12}>
                  <Typography variant="h6">Requirements</Typography>
                  <Box component="ul" sx={{ pl: 2 }}>
                    {selectedJob.requirements?.map((req, i) => (
                      <li key={i}><Typography variant="body2">{req}</Typography></li>
                    ))}
                  </Box>
                </Grid>
                <Grid item xs={12}>
                  <Typography variant="h6">Required Skills</Typography>
                  <Box display="flex" flexWrap="wrap" gap={0.5} mt={1}>
                    {selectedJob.skills_required?.map((skill, i) => (
                      <Chip key={i} label={skill} />
                    ))}
                  </Box>
                </Grid>
              </Grid>
            </DialogContent>
            <DialogActions>
              <Button onClick={() => setDialogOpen(false)}>Close</Button>
              <Button variant="contained" href={selectedJob.apply_url} target="_blank">
                Apply Now
              </Button>
            </DialogActions>
          </>
        )}
      </Dialog>
    </Box>
  );
};

// ==================== SALARY PREDICTOR COMPONENT ====================

const SalaryPredictorPage = () => {
  const [resumes, setResumes] = useState([]);
  const [selectedResume, setSelectedResume] = useState('');
  const [location, setLocation] = useState('');
  const [jobTitle, setJobTitle] = useState('');
  const [prediction, setPrediction] = useState(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => { fetchResumes(); }, []);

  const fetchResumes = async () => {
    try {
      const res = await api.get('/resume/list');
      setResumes(res.data);
    } catch (err) { console.error(err); }
  };

  const predictSalary = async () => {
    if (!selectedResume || !location) {
      alert('Please select a resume and enter location');
      return;
    }
    setLoading(true);
    try {
      const res = await api.post('/salary/predict', {
        resume_id: parseInt(selectedResume),
        location: location,
        job_title: jobTitle || null
      });
      setPrediction(res.data);
    } catch (err) {
      console.error('Salary prediction failed:', err);
      alert('Failed to predict salary');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box>
      <Typography variant="h4" gutterBottom>Salary Predictor</Typography>
      <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>
        Estimate your market value based on skills, experience, and location
      </Typography>

      <Grid container spacing={4}>
        <Grid item xs={12} md={5}>
          <Card sx={{ p: 3 }}>
            <Typography variant="h6" gutterBottom>Your Information</Typography>

            <FormControl fullWidth sx={{ mb: 2 }}>
              <InputLabel>Select Resume</InputLabel>
              <Select
                value={selectedResume}
                onChange={(e) => setSelectedResume(e.target.value)}
                label="Select Resume"
              >
                {resumes.map(r => (
                  <MenuItem key={r.id} value={String(r.id)}>
                    {r.name || r.filename}
                  </MenuItem>
                ))}
              </Select>
            </FormControl>

            <TextField
              fullWidth
              label="Location"
              value={location}
              onChange={(e) => setLocation(e.target.value)}
              placeholder="e.g., San Francisco, CA"
              sx={{ mb: 2 }}
              required
            />

            <TextField
              fullWidth
              label="Job Title (optional)"
              value={jobTitle}
              onChange={(e) => setJobTitle(e.target.value)}
              placeholder="e.g., Senior Software Engineer"
              sx={{ mb: 2 }}
            />

            <Button
              variant="contained"
              fullWidth
              onClick={predictSalary}
              disabled={loading || !selectedResume}
              startIcon={loading ? <CircularProgress size={18} /> : <MoneyIcon />}
              size="large"
            >
              {loading ? 'Predicting...' : 'Predict Salary'}
            </Button>
          </Card>
        </Grid>

        <Grid item xs={12} md={7}>
          {prediction && (
            <Fade in>
              <Box>
                <Card sx={{ mb: 3, background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', color: 'white' }}>
                  <CardContent sx={{ textAlign: 'center', py: 4 }}>
                    <Typography variant="h6" gutterBottom>Estimated Annual Salary</Typography>
                    <Typography variant="h2" fontWeight={800}>
                      ${prediction.estimated_salary?.toLocaleString()}
                    </Typography>
                    <Typography variant="body2">
                      Range: ${prediction.salary_range?.min?.toLocaleString()} - ${prediction.salary_range?.max?.toLocaleString()}
                    </Typography>
                    <Chip
                      label={prediction.market_position}
                      sx={{ mt: 2, bgcolor: 'rgba(255,255,255,0.2)', color: 'white' }}
                    />
                  </CardContent>
                </Card>

                <Card sx={{ mb: 3 }}>
                  <CardContent>
                    <Typography variant="h6" gutterBottom>Salary Breakdown</Typography>
                    <Grid container spacing={2}>
                      <Grid item xs={6}>
                        <Typography variant="body2" color="text.secondary">Base by Experience</Typography>
                        <Typography variant="h6">${prediction.breakdown?.base_by_experience?.toLocaleString()}</Typography>
                      </Grid>
                      <Grid item xs={6}>
                        <Typography variant="body2" color="text.secondary">Skills Premium</Typography>
                        <Typography variant="h6" color="success.main">+{prediction.breakdown?.skills_premium}%</Typography>
                      </Grid>
                      <Grid item xs={6}>
                        <Typography variant="body2" color="text.secondary">Location Adjustment</Typography>
                        <Typography variant="h6" color="warning.main">+{prediction.breakdown?.location_adjustment}%</Typography>
                      </Grid>
                      <Grid item xs={6}>
                        <Typography variant="body2" color="text.secondary">Title Adjustment</Typography>
                        <Typography variant="h6" color="info.main">+{prediction.breakdown?.title_adjustment}%</Typography>
                      </Grid>
                    </Grid>
                  </CardContent>
                </Card>

                <Card>
                  <CardContent>
