const CoverLetterPage = () => {
  const [resumes, setResumes] = useState([]);
  const [selectedResume, setSelectedResume] = useState('');
  const [jobDescription, setJobDescription] = useState('');
  const [companyName, setCompanyName] = useState('');
  const [hiringManager, setHiringManager] = useState('');
  const [tone, setTone] = useState('professional');
  const [coverLetter, setCoverLetter] = useState(null);
  const [loading, setLoading] = useState(false);
  const [copied, setCopied] = useState(false);

  useEffect(() => { fetchResumes(); }, []);

  const fetchResumes = async () => {
    try {
      const res = await api.get('/resume/list');
      setResumes(res.data);
    } catch (err) { console.error(err); }
  };

  const generateCoverLetter = async () => {
    if (!selectedResume || !jobDescription.trim()) {
      alert('Please select a resume and enter job description');
      return;
    }
    setLoading(true);
    try {
      const res = await api.post('/cover-letter/generate', {
        resume_id: parseInt(selectedResume),
        job_description: jobDescription,
        company_name: companyName || null,
        hiring_manager: hiringManager || null,
        tone: tone
      });
      setCoverLetter(res.data);
    } catch (err) {
      console.error('Cover letter generation failed:', err);
      alert('Failed to generate cover letter');
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = () => {
    if (coverLetter?.cover_letter) {
      navigator.clipboard.writeText(coverLetter.cover_letter);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  return (
    <Box>
      <Typography variant="h4" gutterBottom>Cover Letter Generator</Typography>
      <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>
        Create personalized cover letters tailored to any job
      </Typography>

      <Grid container spacing={4}>
        <Grid item xs={12} md={5}>
          <Card sx={{ p: 3 }}>
            <Typography variant="h6" gutterBottom>Job Details</Typography>

            <FormControl fullWidth sx={{ mb: 2 }}>
              <InputLabel>Select Resume</InputLabel>
              <Select
                value={selectedResume}
                onChange={(e) => setSelectedResume(e.target.value)}
                label="Select Resume"
              >
                {resumes.map(r => (
                  <MenuItem key={r.id} value={String(r.id)}>
                    {r.name || r.filename}
                  </MenuItem>
                ))}
              </Select>
            </FormControl>

            <TextField
              fullWidth
              multiline
              rows={6}
              label="Job Description"
              value={jobDescription}
              onChange={(e) => setJobDescription(e.target.value)}
              placeholder="Paste the full job description here..."
              sx={{ mb: 2 }}
            />

            <TextField
              fullWidth
              label="Company Name (optional)"
              value={companyName}
              onChange={(e) => setCompanyName(e.target.value)}
              placeholder="e.g., Google, Microsoft"
              sx={{ mb: 2 }}
            />

            <TextField
              fullWidth
              label="Hiring Manager (optional)"
              value={hiringManager}
              onChange={(e) => setHiringManager(e.target.value)}
              placeholder="e.g., Sarah Johnson"
              sx={{ mb: 2 }}
            />

            <FormControl fullWidth sx={{ mb: 2 }}>
              <InputLabel>Tone</InputLabel>
              <Select
                value={tone}
                onChange={(e) => setTone(e.target.value)}
                label="Tone"
              >
                <MenuItem value="professional">Professional</MenuItem>
                <MenuItem value="enthusiastic">Enthusiastic</MenuItem>
                <MenuItem value="casual">Casual</MenuItem>
              </Select>
            </FormControl>

            <Button
              variant="contained"
              fullWidth
              onClick={generateCoverLetter}
              disabled={loading || !selectedResume || !jobDescription.trim()}
              startIcon={loading ? <CircularProgress size={18} /> : <AutoAwesomeIcon />}
              size="large"
            >
              {loading ? 'Generating...' : 'Generate Cover Letter'}
            </Button>
          </Card>
        </Grid>

        <Grid item xs={12} md={7}>
          {coverLetter && (
            <Fade in>
              <Card>
                <CardContent>
                  <Box display="flex" justifyContent="space-between" alignItems="center" mb={2}>
                    <Typography variant="h6">Your Cover Letter</Typography>
                    <Button
                      startIcon={copied ? <CheckCircleIcon /> : <FileCopyIcon />}
                      onClick={copyToClipboard}
                      variant="outlined"
                      size="small"
                    >
                      {copied ? 'Copied!' : 'Copy to Clipboard'}
                    </Button>
                  </Box>

                  <Typography variant="subtitle2" color="primary" gutterBottom>Subject Line</Typography>
                  <Paper sx={{ p: 2, bgcolor: '#f5f5f5', mb: 2 }}>
                    <Typography variant="body2">{coverLetter.subject_line}</Typography>
                  </Paper>

                  <Typography variant="subtitle2" color="primary" gutterBottom>Cover Letter</Typography>
                  <Paper sx={{ p: 3, bgcolor: '#fff', border: '1px solid #e0e0e0', whiteSpace: 'pre-wrap' }}>
                    <Typography variant="body2" style={{ whiteSpace: 'pre-wrap' }}>
                      {coverLetter.cover_letter}
                    </Typography>
                  </Paper>

                  <Typography variant="subtitle2" color="primary" gutterBottom sx={{ mt: 3 }}>Key Highlights</Typography>
                  <Box display="flex" flexWrap="wrap" gap={1} mb={2}>
                    {coverLetter.key_highlights?.map((highlight, i) => (
                      <Chip key={i} label={highlight} icon={<CheckCircleIcon />} />
                    ))}
                  </Box>

                  <Typography variant="subtitle2" color="primary" gutterBottom>Customization Tips</Typography>
                  <Box component="ul" sx={{ pl: 2 }}>
                    {coverLetter.customization_tips?.map((tip, i) => (
                      <li key={i}><Typography variant="body2">{tip}</Typography></li>
                    ))}
                  </Box>
                </CardContent>
              </Card>
            </Fade>
          )}
        </Grid>
      </Grid>
    </Box>
  );
};

// ==================== ADVANCED ATS ANALYSIS COMPONENT ====================

const AdvancedATSAnalysis = ({ resumeId, refreshKey, onAnalysisComplete }) => {
  const [analysis, setAnalysis] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchAnalysis = async () => {
      if (!resumeId) return;
      setLoading(true);
      setError(null);
      try {
        const response = await api.post('/analyze/advanced-ats', {
          resume_id: parseInt(resumeId)
        });
        setAnalysis(response.data);
        if (onAnalysisComplete) onAnalysisComplete(response.data);
      } catch (error) {
        console.error('Analysis failed:', error);
        setError(error.response?.data?.detail || 'Analysis failed. Please try again.');
        setAnalysis(null);
      } finally {
        setLoading(false);
      }
    };

    fetchAnalysis();
  }, [resumeId, refreshKey, onAnalysisComplete]);

  const getScoreColor = (score) => {
    if (score >= 80) return '#4caf50';
    if (score >= 60) return '#ff9800';
    return '#f44336';
  };

  const getScoreLabel = (score) => {
    if (score >= 80) return 'Excellent';
    if (score >= 70) return 'Good';
    if (score >= 60) return 'Fair';
    if (score >= 50) return 'Needs Work';
    return 'Poor';
  };

  if (loading) {
    return (
      <Card>
        <CardContent sx={{ textAlign: 'center', py: 8 }}>
          <CircularProgress sx={{ color: '#ff69b4' }} />
          <Typography variant="body2" color="text.secondary" mt={2}>Analyzing your resume...</Typography>
        </CardContent>
      </Card>
    );
  }

  if (error) {
    return (
      <Card>
        <CardContent sx={{ textAlign: 'center', py: 8 }}>
          <ErrorIcon sx={{ fontSize: 64, color: '#f44336', mb: 2 }} />
          <Typography variant="h6" gutterBottom color="error">Analysis Error</Typography>
          <Typography variant="body2" color="text.secondary">{error}</Typography>
          <Button variant="contained" onClick={() => window.location.reload()} sx={{ mt: 3 }} startIcon={<RefreshIcon />}>Try Again</Button>
        </CardContent>
      </Card>
    );
  }

  if (!analysis) {
    return (
      <Card>
        <CardContent sx={{ textAlign: 'center', py: 8 }}>
          <PsychologyIcon sx={{ fontSize: 64, color: alpha('#ff69b4', 0.3), mb: 2 }} />
          <Typography variant="h6" gutterBottom>No Analysis Yet</Typography>
          <Typography variant="body2" color="text.secondary">Select a resume and click "Refresh Analysis" to get detailed insights</Typography>
        </CardContent>
      </Card>
    );
  }

  return (
    <Box>
      <Card sx={{ mb: 3, background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', color: 'white' }}>
        <CardContent>
          <Grid container spacing={3} alignItems="center">
            <Grid item xs={12} md={4} textAlign="center">
              <Box position="relative" display="inline-flex">
                <CircularProgress variant="determinate" value={analysis.ats_score || 0} size={150} thickness={4} sx={{ color: 'white' }} />
                <Box position="absolute" top="50%" left="50%" textAlign="center" sx={{ transform: 'translate(-50%, -50%)' }}>
                  <Typography variant="h2" fontWeight="bold">{Math.round(analysis.ats_score || 0)}</Typography>
                  <Typography variant="caption">/100</Typography>
                </Box>
              </Box>
              <Typography variant="h6" mt={1}>{getScoreLabel(analysis.ats_score || 0)}</Typography>
            </Grid>
            <Grid item xs={12} md={8}>
              <Grid container spacing={2}>
                <Grid item xs={6}>
                  <Typography variant="caption" opacity={0.8}>Percentile Rank</Typography>
                  <Typography variant="h5">{analysis.percentile_rank || 65}%</Typography>
                </Grid>
                <Grid item xs={6}>
                  <Typography variant="caption" opacity={0.8}>Confidence Interval</Typography>
                  <Typography variant="h5">{analysis.confidence_interval || '±5'}</Typography>
                </Grid>
              </Grid>
            </Grid>
          </Grid>
        </CardContent>
      </Card>

      <Typography variant="h6" gutterBottom>Detailed Score Breakdown</Typography>
      <Grid container spacing={2} sx={{ mb: 3 }}>
        {Object.entries(analysis.score_breakdown || {}).map(([category, score]) => (
          <Grid item xs={12} sm={6} md={4} key={category}>
            <Card>
              <CardContent>
                <Box display="flex" justifyContent="space-between" alignItems="center" mb={1}>
                  <Typography variant="h6" textTransform="capitalize">{category.replace(/_/g, ' ')}</Typography>
                  <Typography variant="h5" fontWeight="bold" sx={{ color: getScoreColor(score) }}>{Math.round(score)}</Typography>
                </Box>
                <LinearProgress variant="determinate" value={score} sx={{ height: 8, borderRadius: 4 }} />
              </CardContent>
            </Card>
          </Grid>
        ))}
      </Grid>

      <Grid container spacing={3}>
        <Grid item xs={12} md={6}>
          <Card><CardContent>
            <Typography variant="h6" gutterBottom>💪 Strengths</Typography>
            {(analysis.strengths || []).map((strength, idx) => (
              <Box key={idx} display="flex" alignItems="center" gap={1} mb={1}>
                <CheckCircleIcon sx={{ color: '#4caf50', fontSize: 20 }} />
                <Typography variant="body2">{strength}</Typography>
              </Box>
            ))}
          </CardContent></Card>
        </Grid>
        <Grid item xs={12} md={6}>
          <Card><CardContent>
            <Typography variant="h6" gutterBottom>⚠️ Areas for Improvement</Typography>
            {(analysis.weaknesses || []).map((weakness, idx) => (
              <Box key={idx} display="flex" alignItems="center" gap={1} mb={1}>
                <WarningIcon sx={{ color: '#ff9800', fontSize: 20 }} />
                <Typography variant="body2">{weakness}</Typography>
              </Box>
            ))}
          </CardContent></Card>
        </Grid>
        <Grid item xs={12}>
          <Card sx={{ bgcolor: '#e3f2fd' }}><CardContent>
            <Typography variant="h6" gutterBottom>💡 Actionable Suggestions</Typography>
            <Grid container spacing={1}>
              {(analysis.suggestions || []).map((suggestion, idx) => (
                <Grid item xs={12} sm={6} key={idx}>
                  <Box display="flex" alignItems="center" gap={1}>
                    <TrendingUpIcon sx={{ color: '#2196f3', fontSize: 20 }} />
                    <Typography variant="body2">{suggestion}</Typography>
                  </Box>
                </Grid>
              ))}
            </Grid>
          </CardContent></Card>
        </Grid>
      </Grid>
    </Box>
  );
};

