        <Toolbar>
          <IconButton color="inherit" edge="start" onClick={() => setMobileOpen(!mobileOpen)} sx={{ mr: 2, display: { md: 'none' } }}><MenuIcon /></IconButton>
          <AnalyticsIcon sx={{ mr: 1 }} />
          <Typography variant="h6" fontWeight={700} sx={{ flexGrow: 1, cursor: 'pointer' }} onClick={() => navigate('/')}>ResumeAI</Typography>
          <Chip avatar={<Avatar sx={{ bgcolor: 'white', color: '#ff69b4', width: 28, height: 28, fontSize: 13 }}>{user?.username?.[0]?.toUpperCase()}</Avatar>} label={user?.username} sx={{ color: 'white', borderColor: 'rgba(255,255,255,0.5)', mr: 1 }} variant="outlined" />
          <IconButton color="inherit" onClick={logout} title="Logout"><LogoutIcon /></IconButton>
        </Toolbar>
      </AppBar>

      <Drawer variant="permanent" sx={{ display: { xs: 'none', md: 'block' }, width: drawerWidth, flexShrink: 0, '& .MuiDrawer-paper': { width: drawerWidth, mt: 8, borderRight: '1px solid #fce4ec' } }} open>{drawerContent}</Drawer>
      <Drawer variant="temporary" open={mobileOpen} onClose={() => setMobileOpen(false)} sx={{ display: { xs: 'block', md: 'none' }, '& .MuiDrawer-paper': { width: drawerWidth } }}>{drawerContent}</Drawer>

      <Box component="main" sx={{ flexGrow: 1, p: 3, width: { xs: '100%', md: `calc(100% - ${drawerWidth}px)` }, mt: 8, backgroundColor: '#fff5f8', minHeight: '100vh' }}>{children}</Box>
    </Box>
  );
};

// ==================== DASHBOARD ====================

const DashboardPage = () => {
  const [resumes, setResumes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({ total: 0, avgScore: 0, totalMatches: 0 });
  const [deleting, setDeleting] = useState(null);

  useEffect(() => { fetchData(); }, []);

  const fetchData = async () => {
    try {
      const [resumesRes, historyRes] = await Promise.all([api.get('/resume/list'), api.get('/analysis/history')]);
      setResumes(resumesRes.data);
      const ats = historyRes.data.filter(a => a.analysis_type === 'ats_score');
      const avgScore = ats.length ? Math.round(ats.reduce((s, a) => s + (a.ats_score || 0), 0) / ats.length) : 0;
      const matches = historyRes.data.filter(a => a.analysis_type === 'job_match').length;
      setStats({ total: resumesRes.data.length, avgScore, totalMatches: matches });
    } catch (err) { console.error(err); } finally { setLoading(false); }
  };

  const handleDelete = async (id) => {
    setDeleting(id);
    try { await api.delete(`/resume/${id}`); setResumes(prev => prev.filter(r => r.id !== id)); } catch (err) { console.error(err); } finally { setDeleting(null); }
  };

  if (loading) return <Box display="flex" justifyContent="center" alignItems="center" minHeight="60vh"><CircularProgress sx={{ color: '#ff69b4' }} /></Box>;

  return (
    <Box>
      <Typography variant="h4" gutterBottom>Welcome Back! 👋</Typography>
      <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>Here's an overview of your resume activity</Typography>

      <Grid container spacing={3} sx={{ mb: 4 }}>
        {[
          { label: 'Total Resumes', value: stats.total, icon: <DescriptionIcon sx={{ fontSize: 40, color: '#ff69b4' }} />, color: '#ff69b4' },
          { label: 'Avg ATS Score', value: `${stats.avgScore}%`, icon: <TrendingUpIcon sx={{ fontSize: 40, color: '#51cf66' }} />, color: '#51cf66' },
          { label: 'Job Matches', value: stats.totalMatches, icon: <WorkIcon sx={{ fontSize: 40, color: '#ff922b' }} />, color: '#ff922b' },
        ].map((stat, i) => (
          <Grid item xs={12} sm={4} key={i}>
            <Card sx={{ p: 3 }}>
              <Box display="flex" justifyContent="space-between" alignItems="center">
                <Box><Typography color="text.secondary" variant="body2">{stat.label}</Typography><Typography variant="h3" fontWeight={700}>{stat.value}</Typography></Box>
                <Box sx={{ bgcolor: alpha(stat.color, 0.1), borderRadius: 2, p: 1.5 }}>{stat.icon}</Box>
              </Box>
            </Card>
          </Grid>
        ))}
      </Grid>

      <Box>
        <Box display="flex" justifyContent="space-between" alignItems="center" sx={{ mb: 3 }}>
          <Typography variant="h5">My Resumes</Typography>
          <Button variant="contained" startIcon={<AddIcon />} component={Link} to="/upload">Upload Resume</Button>
        </Box>

        {resumes.length === 0 ? (
          <Card sx={{ textAlign: 'center', py: 10 }}>
            <InsertDriveFileIcon sx={{ fontSize: 80, color: alpha('#ff69b4', 0.3), mb: 2 }} />
            <Typography variant="h6" gutterBottom>No resumes yet</Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>Upload your first resume to get started</Typography>
            <Button variant="contained" component={Link} to="/upload" startIcon={<CloudUploadIcon />}>Upload Resume</Button>
          </Card>
        ) : (
          <Grid container spacing={3}>
            {resumes.map((resume) => (
              <Grid item xs={12} sm={6} md={4} key={resume.id}>
                <Card>
                  <CardContent>
                    <Box display="flex" alignItems="center" gap={2} mb={2}>
                      <Avatar sx={{ bgcolor: '#ff69b4', width: 44, height: 44 }}>{resume.name?.[0] || <DescriptionIcon />}</Avatar>
                      <Box sx={{ minWidth: 0 }}>
                        <Typography variant="h6" noWrap fontWeight={600}>{resume.name || 'Unnamed Resume'}</Typography>
                        <Typography variant="caption" color="text.secondary" noWrap display="block">{resume.filename}</Typography>
                      </Box>
                    </Box>
                    {resume.skills?.length > 0 && (
                      <Box>
                        <Typography variant="caption" color="text.secondary" fontWeight={600}>SKILLS DETECTED</Typography>
                        <Box display="flex" flexWrap="wrap" gap={0.5} mt={0.5}>
                          {resume.skills.slice(0, 4).map(s => (<Chip key={s} label={s} size="small" sx={{ bgcolor: alpha('#ff69b4', 0.1), fontSize: 11 }} />))}
                          {resume.skills.length > 4 && (<Chip label={`+${resume.skills.length - 4}`} size="small" sx={{ bgcolor: '#f5f5f5', fontSize: 11 }} />)}
                        </Box>
                      </Box>
                    )}
                  </CardContent>
                  <Divider />
                  <CardActions sx={{ px: 2, py: 1 }}>
                    <Button size="small" startIcon={<AssessmentIcon />} component={Link} to={`/analyze?resume=${resume.id}`} sx={{ color: '#ff69b4' }}>Analyze</Button>
                    <Button size="small" startIcon={<WorkIcon />} component={Link} to={`/match?resume=${resume.id}`} sx={{ color: '#ff922b' }}>Match Job</Button>
                    <Box sx={{ flexGrow: 1 }} />
                    <IconButton size="small" color="error" onClick={() => handleDelete(resume.id)} disabled={deleting === resume.id}>{deleting === resume.id ? <CircularProgress size={16} /> : <DeleteIcon fontSize="small" />}</IconButton>
                  </CardActions>
                </Card>
              </Grid>
            ))}
          </Grid>
        )}
      </Box>
    </Box>
  );
};

// ==================== UPLOAD ====================

const UploadPage = () => {
  const [file, setFile] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState('');

  const handleUpload = async () => {
    if (!file) { setError('Please select a file first'); return; }
    setError('');
    setResult(null);
    setUploading(true);
    try {
      const formData = new FormData();
      formData.append('file', file);
      const res = await api.post('/resume/upload', formData, { headers: { 'Content-Type': 'multipart/form-data' } });
      setResult(res.data);
    } catch (err) {
      setError(err.response?.data?.detail || 'Upload failed');
    } finally {
      setUploading(false);
    }
  };

  return (
    <Box>
      <Typography variant="h4" gutterBottom>Upload Resume</Typography>
      <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>Upload a PDF or DOCX resume to start analyzing</Typography>

      <Grid container spacing={4}>
        <Grid item xs={12} md={7}>
          <Card sx={{ p: 3 }}>
            <FileDropZone file={file} onFileChange={(f) => { setFile(f); setResult(null); setError(''); }} />
            <Box sx={{ mt: 3, display: 'flex', gap: 2 }}>
              <Button variant="contained" fullWidth onClick={handleUpload} disabled={!file || uploading} startIcon={uploading ? <CircularProgress size={18} /> : <CloudUploadIcon />} size="large">{uploading ? 'Uploading...' : 'Upload Resume'}</Button>
              {file && <Button variant="outlined" onClick={() => { setFile(null); setResult(null); setError(''); }}>Clear</Button>}
            </Box>
            {error && <Alert severity="error" sx={{ mt: 2 }}>{error}</Alert>}
            {result && (<Fade in><Alert severity="success" sx={{ mt: 2 }}><Typography fontWeight={600}>✅ Resume uploaded successfully!</Typography>{result.name && <Typography variant="body2">Name: {result.name}</Typography>}{result.email && <Typography variant="body2">Email: {result.email}</Typography>}</Alert></Fade>)}
            {result && (<Box sx={{ mt: 2, display: 'flex', gap: 2 }}><Button variant="contained" component={Link} to={`/analyze?resume=${result.id}`} startIcon={<AssessmentIcon />}>Analyze Now</Button><Button variant="outlined" component={Link} to="/dashboard" startIcon={<DashboardIcon />}>Go to Dashboard</Button></Box>)}
          </Card>
        </Grid>
        <Grid item xs={12} md={5}>
          <Card sx={{ p: 3, bgcolor: '#fff0f5', mb: 3 }}>
            <Typography variant="h6" gutterBottom>Supported Formats</Typography>
            <Box display="flex" gap={2} sx={{ mb: 2 }}><Chip icon={<PictureAsPdfIcon />} label="PDF" /><Chip icon={<ArticleIcon />} label="DOCX" /></Box>
            <Typography variant="body2" color="text.secondary">Max file size: 10MB</Typography>
          </Card>
        </Grid>
      </Grid>
    </Box>
  );
};

// ==================== ATS ANALYSIS PAGE ====================

const ATSAnalysisPage = () => {
  const [resumes, setResumes] = useState([]);
  const [selectedResume, setSelectedResume] = useState('');
  const [analyzing, setAnalyzing] = useState(false);
  const [error, setError] = useState('');
  const [refreshKey, setRefreshKey] = useState(0);
  const location = useLocation();

  useEffect(() => { fetchResumes(); }, []);
  useEffect(() => { const params = new URLSearchParams(location.search); const id = params.get('resume'); if (id) setSelectedResume(id); }, [location.search]);

  const fetchResumes = async () => { try { const res = await api.get('/resume/list'); setResumes(res.data); } catch (err) { console.error(err); } };
  const handleAnalyze = () => { if (!selectedResume) { setError('Please select a resume first'); return; } setAnalyzing(true); setError(''); setRefreshKey(prev => prev + 1); setTimeout(() => setAnalyzing(false), 500); };

  return (
    <Box>
      <Typography variant="h4" gutterBottom>ATS Analysis</Typography>
      <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>Analyze how well your resume performs against ATS systems</Typography>

      <Grid container spacing={4}>
        <Grid item xs={12} md={4}>
          <Card sx={{ p: 3, position: 'sticky', top: 80 }}>
            <Typography variant="h6" gutterBottom>Select Resume</Typography>
            <FormControl fullWidth sx={{ mb: 2 }}><InputLabel>Choose a resume</InputLabel><Select value={selectedResume} onChange={(e) => setSelectedResume(e.target.value)} label="Choose a resume">{resumes.map(r => (<MenuItem key={r.id} value={String(r.id)}>{r.name || r.filename}</MenuItem>))}</Select></FormControl>
            <Button variant="contained" fullWidth onClick={handleAnalyze} disabled={!selectedResume || analyzing} size="large" startIcon={analyzing ? <CircularProgress size={18} /> : <AutoAwesomeIcon />}>{analyzing ? 'Refreshing...' : 'Refresh Analysis'}</Button>
            {error && <Alert severity="error" sx={{ mt: 2 }}>{error}</Alert>}
            <Box sx={{ mt: 3, p: 2, bgcolor: '#fff0f5', borderRadius: 2 }}><Typography variant="body2" fontWeight={600}>✨ Advanced Features</Typography><Typography variant="body2" color="text.secondary">• Detailed score breakdown<br/>• Historical score tracking<br/>• Gap analysis<br/>• AI-powered suggestions</Typography></Box>
          </Card>
        </Grid>
        <Grid item xs={12} md={8}>{selectedResume ? (<AdvancedATSAnalysis resumeId={selectedResume} refreshKey={refreshKey} onAnalysisComplete={(data) => console.log('Analysis complete:', data)} />) : (<Card sx={{ textAlign: 'center', py: 10 }}><PsychologyIcon sx={{ fontSize: 80, color: alpha('#ff69b4', 0.3), mb: 2 }} /><Typography variant="h6">No resume selected</Typography><Typography variant="body2" color="text.secondary">Select a resume from the left to start analysis</Typography></Card>)}</Grid>
      </Grid>
    </Box>
  );
};

// ==================== JOB MATCHER ====================

const JobMatcherPage = () => {
  const [resumes, setResumes] = useState([]);
  const [selectedResume, setSelectedResume] = useState('');
  const [jobDescription, setJobDescription] = useState('');
  const [match, setMatch] = useState(null);
  const [matching, setMatching] = useState(false);
  const [error, setError] = useState('');
  const [openDialog, setOpenDialog] = useState(false);
  const location = useLocation();

  useEffect(() => { fetchResumes(); }, []);
  useEffect(() => { const params = new URLSearchParams(location.search); const id = params.get('resume'); if (id) setSelectedResume(id); }, [location.search]);

  const fetchResumes = async () => { try { const res = await api.get('/resume/list'); setResumes(res.data); } catch (err) { console.error(err); } };
  const handleMatch = async () => { if (!selectedResume || !jobDescription.trim()) return; setMatching(true); setError(''); try { const res = await api.post('/analyze/match-job', { resume_id: parseInt(selectedResume), job_description: jobDescription }); setMatch(res.data); setOpenDialog(true); } catch (err) { setError(err.response?.data?.detail || 'Job matching failed'); } finally { setMatching(false); } };
  const getMatchColor = (pct) => { if (pct >= 80) return '#51cf66'; if (pct >= 60) return '#ff922b'; return '#ff6b6b'; };

  return (
    <Box>
      <Typography variant="h4" gutterBottom>Job Matcher</Typography>
      <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>Paste a job description and see how well your resume matches</Typography>

      <Grid container spacing={4}>
        <Grid item xs={12} md={4}><Card sx={{ p: 3 }}><Typography variant="h6" gutterBottom>Select Resume</Typography><FormControl fullWidth><InputLabel>Choose a resume</InputLabel><Select value={selectedResume} onChange={(e) => setSelectedResume(e.target.value)} label="Choose a resume">{resumes.map(r => (<MenuItem key={r.id} value={String(r.id)}>{r.name || r.filename}</MenuItem>))}</Select></FormControl></Card></Grid>
        <Grid item xs={12} md={8}><Card sx={{ p: 3 }}><Typography variant="h6" gutterBottom>Job Description</Typography><TextField fullWidth multiline rows={10} placeholder="Paste the full job description here..." value={jobDescription} onChange={(e) => setJobDescription(e.target.value)} sx={{ mb: 3 }} />{error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}<Button variant="contained" fullWidth onClick={handleMatch} disabled={!selectedResume || !jobDescription.trim() || matching} size="large" startIcon={matching ? <CircularProgress size={18} /> : <WorkIcon />}>{matching ? 'Matching...' : 'Match Resume with Job'}</Button></Card></Grid>
      </Grid>

      <Dialog open={openDialog} onClose={() => setOpenDialog(false)} maxWidth="md" fullWidth><DialogTitle><Box display="flex" justifyContent="space-between"><Typography variant="h5">Match Results</Typography>{match && (<Box textAlign="center"><Typography variant="h2" fontWeight={800} sx={{ color: getMatchColor(match.match_percentage) }}>{Math.round(match.match_percentage)}%</Typography></Box>)}</Box></DialogTitle><DialogContent dividers>{match && (<Box><LinearProgress variant="determinate" value={match.match_percentage} sx={{ mb: 3, height: 10, borderRadius: 5 }} />{match.role_fit_summary && (<Box sx={{ mb: 3, p: 2, bgcolor: '#fff0f5', borderRadius: 2 }}><Typography variant="body2">{match.role_fit_summary}</Typography></Box>)}<Grid container spacing={3}>{match.matched_skills?.length > 0 && (<Grid item xs={12} sm={6}><Typography variant="subtitle2" fontWeight={700}>✅ Matched Skills ({match.matched_skills.length})</Typography><Box display="flex" flexWrap="wrap" gap={0.8}>{match.matched_skills.map((s, i) => (<Chip key={i} label={s} size="small" color="success" />))}</Box></Grid>)}{match.missing_skills?.length > 0 && (<Grid item xs={12} sm={6}><Typography variant="subtitle2" fontWeight={700}>❌ Missing Skills ({match.missing_skills.length})</Typography><Box display="flex" flexWrap="wrap" gap={0.8}>{match.missing_skills.map((s, i) => (<Chip key={i} label={s} size="small" color="error" />))}</Box></Grid>)}</Grid></Box>)}</DialogContent><DialogActions><Button onClick={() => setOpenDialog(false)} variant="outlined">Close</Button><Button variant="contained" component={Link} to="/history">View History</Button></DialogActions></Dialog>
    </Box>
  );
};

// ==================== HISTORY ====================

const HistoryPage = () => {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');

  useEffect(() => { fetchHistory(); }, []);
  const fetchHistory = async () => { try { const res = await api.get('/analysis/history'); setHistory(res.data); } catch (err) { console.error(err); } finally { setLoading(false); } };
  const filtered = filter === 'all' ? history : history.filter(i => i.analysis_type === filter);
  const getScore = (item) => { if (item.analysis_type === 'ats_score') return item.ats_score; return item.match_percentage; };
  const getScoreColor = (score) => { if (!score) return '#9e9e9e'; if (score >= 80) return '#51cf66'; if (score >= 60) return '#ff922b'; return '#ff6b6b'; };

  if (loading) return <Box display="flex" justifyContent="center" alignItems="center" minHeight="60vh"><CircularProgress sx={{ color: '#ff69b4' }} /></Box>;

  return (
    <Box>
      <Typography variant="h4" gutterBottom>Analysis History</Typography>
      <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>Review all your past resume analyses</Typography>
      <Box sx={{ mb: 3 }}><ToggleButtonGroup value={filter} exclusive onChange={(e, v) => v && setFilter(v)}><ToggleButton value="all">All ({history.length})</ToggleButton><ToggleButton value="ats_score">ATS Scores ({history.filter(i => i.analysis_type === 'ats_score').length})</ToggleButton><ToggleButton value="job_match">Job Matches ({history.filter(i => i.analysis_type === 'job_match').length})</ToggleButton></ToggleButtonGroup></Box>
      {filtered.length === 0 ? (<Paper sx={{ textAlign: 'center', py: 10 }}><HistoryIcon sx={{ fontSize: 80, color: alpha('#ff69b4', 0.3), mb: 2 }} /><Typography variant="h6">No history yet</Typography><Typography variant="body2" color="text.secondary">Analyze a resume or match it with a job to see results here</Typography></Paper>) : (<Grid container spacing={2}>{filtered.map((item) => { const score = getScore(item); return (<Grid item xs={12} sm={6} md={4} key={item.id}><Card sx={{ p: 2.5 }}><Box display="flex" justifyContent="space-between"><Box><Typography variant="h6" noWrap>{item.resume_name}</Typography><Typography variant="caption" color="text.secondary">{new Date(item.created_at).toLocaleDateString()}</Typography><Chip label={item.analysis_type === 'ats_score' ? 'ATS Score' : 'Job Match'} size="small" sx={{ mt: 1, bgcolor: alpha('#ff69b4', 0.1) }} /></Box><Typography variant="h3" fontWeight={800} sx={{ color: getScoreColor(score) }}>{score ? Math.round(score) : '—'}</Typography></Box></Card></Grid>); })}</Grid>)}
    </Box>
  );
};

// ==================== LOGIN ====================

const LoginPage = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => { e.preventDefault(); setLoading(true); setError(''); try { await login(username, password); navigate('/dashboard'); } catch (err) { setError(err.response?.data?.detail || 'Invalid username or password'); } finally { setLoading(false); } };

  return (<Box sx={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'linear-gradient(135deg, #ff69b4 0%, #ff1493 100%)' }}><Container maxWidth="sm"><Card sx={{ p: 4 }}><Box textAlign="center" mb={4}><Avatar sx={{ bgcolor: '#ff69b4', width: 64, height: 64, margin: '0 auto', mb: 2 }}><AnalyticsIcon sx={{ fontSize: 32 }} /></Avatar><Typography variant="h4" fontWeight={700}>Welcome Back</Typography></Box><form onSubmit={handleSubmit}><TextField fullWidth label="Username" value={username} onChange={(e) => setUsername(e.target.value)} margin="normal" required autoFocus /><TextField fullWidth label="Password" type="password" value={password} onChange={(e) => setPassword(e.target.value)} margin="normal" required />{error && <Alert severity="error" sx={{ mt: 2 }}>{error}</Alert>}<Button type="submit" fullWidth variant="contained" size="large" disabled={loading} sx={{ mt: 3 }}>{loading ? <CircularProgress size={24} /> : 'Sign In'}</Button></form><Box textAlign="center" mt={3}><Typography variant="body2">Don't have an account? <Link to="/signup" style={{ color: '#ff69b4' }}>Sign Up</Link></Typography></Box></Card></Container></Box>);
};

// ==================== SIGNUP ====================

const SignupPage = () => {
  const [formData, setFormData] = useState({ username: '', email: '', password: '' });
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);
  const [loading, setLoading] = useState(false);
  const { signup } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => { e.preventDefault(); setLoading(true); setError(''); try { await signup(formData); setSuccess(true); setTimeout(() => navigate('/login'), 2000); } catch (err) { setError(err.response?.data?.detail || 'Signup failed'); } finally { setLoading(false); } };
  const update = (key) => (e) => setFormData(prev => ({ ...prev, [key]: e.target.value }));

  return (<Box sx={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'linear-gradient(135deg, #ff69b4 0%, #ff1493 100%)' }}><Container maxWidth="sm"><Card sx={{ p: 4 }}><Box textAlign="center" mb={4}><Avatar sx={{ bgcolor: '#ff69b4', width: 64, height: 64, margin: '0 auto', mb: 2 }}><AppRegistrationIcon sx={{ fontSize: 32 }} /></Avatar><Typography variant="h4" fontWeight={700}>Create Account</Typography></Box><form onSubmit={handleSubmit}><TextField fullWidth label="Username" value={formData.username} onChange={update('username')} margin="normal" required autoFocus /><TextField fullWidth label="Email" type="email" value={formData.email} onChange={update('email')} margin="normal" required /><TextField fullWidth label="Password" type="password" value={formData.password} onChange={update('password')} margin="normal" required inputProps={{ minLength: 6 }} />{error && <Alert severity="error" sx={{ mt: 2 }}>{error}</Alert>}{success && <Alert severity="success" sx={{ mt: 2 }}>Account created! Redirecting...</Alert>}<Button type="submit" fullWidth variant="contained" size="large" disabled={loading || success} sx={{ mt: 3 }}>{loading ? <CircularProgress size={24} /> : 'Create Account'}</Button></form><Box textAlign="center" mt={3}><Typography variant="body2">Already have an account? <Link to="/login" style={{ color: '#ff69b4' }}>Sign In</Link></Typography></Box></Card></Container></Box>);
};

// ==================== APP ====================

const AppRoutes = () => {
  const { user, loading } = useAuth();
  if (loading) return <Box display="flex" justifyContent="center" alignItems="center" minHeight="100vh"><CircularProgress sx={{ color: '#ff69b4' }} size={48} /></Box>;
  return (<Routes><Route path="/" element={<HomePage />} /><Route path="/login" element={user ? <Navigate to="/dashboard" /> : <LoginPage />} /><Route path="/signup" element={user ? <Navigate to="/dashboard" /> : <SignupPage />} /><Route path="/dashboard" element={user ? <Layout><DashboardPage /></Layout> : <Navigate to="/login" />} /><Route path="/upload" element={user ? <Layout><UploadPage /></Layout> : <Navigate to="/login" />} /><Route path="/analyze" element={user ? <Layout><ATSAnalysisPage /></Layout> : <Navigate to="/login" />} /><Route path="/match" element={user ? <Layout><JobMatcherPage /></Layout> : <Navigate to="/login" />} /><Route path="/history" element={user ? <Layout><HistoryPage /></Layout> : <Navigate to="/login" />} /><Route path="/jobs" element={user ? <Layout><JobBoardPage /></Layout> : <Navigate to="/login" />} /><Route path="/salary" element={user ? <Layout><SalaryPredictorPage /></Layout> : <Navigate to="/login" />} /><Route path="/career" element={user ? <Layout><CareerPathPage /></Layout> : <Navigate to="/login" />} /><Route path="/cover-letter" element={user ? <Layout><CoverLetterPage /></Layout> : <Navigate to="/login" />} /><Route path="*" element={<Navigate to="/" />} /></Routes>);
};

const App = () => (<ThemeProvider theme={theme}><CssBaseline /><AuthProvider><Router><AppRoutes /></Router></AuthProvider></ThemeProvider>);

export default App;
